impl Solution {
    pub fn lowest_common_ancestor(
        root: Option<Box<TreeNode>>,
        p: Option<Box<TreeNode>>,
        q: Option<Box<TreeNode>>,
    ) -> Option<Box<TreeNode>> {
        Self::lca(&root, &p, &q)
    }

    fn lca(
        node: &Option<Box<TreeNode>>,
        p: &Option<Box<TreeNode>>,
        q: &Option<Box<TreeNode>>,
    ) -> Option<Box<TreeNode>> {
        match node {
            None => None,
            Some(n) => {
                if p.as_ref().map_or(false, |x| x.val == n.val)
                    || q.as_ref().map_or(false, |x| x.val == n.val)
                {
                    return Some(Box::new(TreeNode {
                        val: n.val,
                        left: None,
                        right: None,
                    }));
                }
                let left = Self::lca(&n.left, p, q);
                let right = Self::lca(&n.right, p, q);
                match (&left, &right) {
                    (Some(_), Some(_)) => Some(Box::new(TreeNode {
                        val: n.val,
                        left: None,
                        right: None,
                    })),
                    (Some(_), None) => left,
                    (None, Some(_)) => right,
                    (None, None) => None,
                }
            }
        }
    }
}

