struct Codec;

impl Codec {
    fn new() -> Self {
        Codec
    }

    fn serialize(&self, root: Option<Box<TreeNode>>) -> String {
        match root {
            None => "null".to_string(),
            Some(node) => {
                format!("{},{},{}",
                    node.val,
                    self.serialize(node.left),
                    self.serialize(node.right)
                )
            }
        }
    }

    fn deserialize(&self, data: String) -> Option<Box<TreeNode>> {
        let mut nodes: Vec<&str> = data.split(',').collect();
        let mut index = 0;
        Self::dfs(&nodes, &mut index)
    }

    fn dfs(nodes: &Vec<&str>, index: &mut usize) -> Option<Box<TreeNode>> {
        if *index >= nodes.len() {
            return None;
        }
        let val = nodes[*index];
        *index += 1;
        if val == "null" {
            return None;
        }
        let v: i32 = val.parse().unwrap();
        Some(Box::new(TreeNode {
            val: v,
            left: Self::dfs(nodes, index),
            right: Self::dfs(nodes, index),
        }))
    }
}
